```c
#include <stdio.h>

int main() {
    int a, b, w, x, c;
    scanf("%d %d %d %d %d", &a, &b, &w, &x, &c);

    if (c <= a) {
        printf("0\n");
        return 0;
    }

    long long l = 0, r = (c - a) * 10000LL;
    while (l + 1 < r) {
        long long m = (l + r) / 2;

        if (c - m <= a - (w - b - 1 + m * x) / w) {
            r = m;
        } else {
            l = m;
        }
    }

    printf("%lld\n", r);
    return 0;
}
